{
  "name": "azure-primary-{{$guid}}",
  "provider": "azure",
  "description": "Azure OpenAI registry using OAuth service principal auth",
  "auth": {
    "type": "azure",
    "azure": {
      "endpoint": "{{azure_openai_endpoint}}",
      "version": "2024-10-21",
      "tenant_id": "{{azure_tenant_id}}",
      "client_id": "{{azure_client_id}}",
      "client_secret": "{{azure_client_secret}}"
    }
  }
}

{
  "name": "azure-default-credential-{{$guid}}",
  "provider": "azure",
  "description": "Azure OpenAI using Azure SDK DefaultAzureCredential",
  "auth": {
    "type": "azure",
    "azure": {
      "endpoint": "{{azure_openai_endpoint}}",
      "version": "2024-10-21",
      "use_managed_identity": true
    }
  }
}

{
  "description": "Rotate metadata without resending the Azure API key",
  "auth": {
    "type": "azure",
    "azure": {
      "endpoint": "{{azure_openai_endpoint}}",
      "version": "2024-10-21",
      "api_key": "***"
    }
  }
}

{
  "name": "azure-oauth-{{$guid}}",
  "provider": "azure",
  "description": "Azure OpenAI registry using OAuth service principal auth",
  "auth": {
    "type": "azure",
    "azure": {
      "endpoint": "{{azure_openai_endpoint}}",
      "version": "2024-10-21",
      "tenant_id": "{{azure_tenant_id}}",
      "client_id": "{{azure_client_id}}",
      "client_secret": "{{azure_client_secret}}"
    }
  }
}

{
  "name": "azure-api-key-{{$guid}}",
  "provider": "azure",
  "description": "Azure OpenAI registry using API key auth",
  "auth": {
    "type": "azure",
    "azure": {
      "endpoint": "{{azure_openai_endpoint}}",
      "version": "2024-10-21",
      "api_key": "{{azure_openai_api_key}}"
    }
  }
}

{
  "name": "prompt-template-mode-a-{{$guid}}",
  "slug": "prompt_template",
  "enabled": true,
  "priority": 10,
  "parallel": false,
  "stages": [
    "pre_request"
  ],
  "settings": {
    "context_variables": {
      "tenant_tier": {
        "source": "header",
        "name": "X-Tenant-Tier"
      }
    },
    "inject_templates": [
      {
        "id": "tenant-system-prompt",
        "position": "system",
        "role": "system",
        "content": "You are a helpful assistant for {{tenant_tier}} customers.",
        "on_existing_system": "merge"
      }
    ],
    "on_missing_context_variable": "error",
    "allow_untemplated_requests": true
  }
}

{
  "name": "prompt-template-mode-b-{{$guid}}",
  "slug": "prompt_template",
  "enabled": true,
  "priority": 10,
  "parallel": false,
  "stages": [
    "pre_request"
  ],
  "settings": {
    "named_templates": [
      {
        "name": "support-bot",
        "versions": [
          {
            "labels": [
              "latest",
              "published"
            ],
            "content": "[{\"role\":\"system\",\"content\":\"You are a {{persona}} support agent.\"},{\"role\":\"user\",\"content\":\"{{question}}\"}]",
            "required_variables": {
              "persona": {
                "type": "string",
                "enum": [
                  "friendly",
                  "formal"
                ]
              },
              "question": {
                "type": "string",
                "max_length": 200
              }
            }
          }
        ]
      }
    ],
    "default_label": "published",
    "allow_untemplated_requests": false,
    "on_missing_client_variable": "error",
    "escape_json_control_chars": true
  }
}

